// model-config.ts — single source of truth for model assignments
export const MODEL_CONFIG = {
  // Primary models by capability tier
  reasoning: 'claude-opus-4-8',
  balanced: 'claude-sonnet-5',
  fast: 'claude-haiku-4-5-20251001',

  // Per-feature assignments (allows independent migration)
  features: {
    documentSummarization: 'claude-sonnet-5',
    intentClassification: 'claude-haiku-4-5-20251001',
    complexAnalysis: 'claude-opus-4-8',
    codeReview: 'claude-sonnet-5',
  },

  // Fallback model used during burst or on primary model errors
  fallback: 'claude-haiku-4-5-20251001',
} as const;

export type FeatureKey = keyof typeof MODEL_CONFIG.features;

// Use in application code — never inline model strings
import { MODEL_CONFIG } from './model-config';

