  model: MODEL_CONFIG.features.documentSummarization,
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }],
});

// Validate model config at startup — catch deprecation early
import Anthropic from '@anthropic-ai/sdk';
import { MODEL_CONFIG } from './model-config';

async function validateModelConfig(client: Anthropic): Promise<void> {
  const allModels = new Set([
    MODEL_CONFIG.reasoning,
    MODEL_CONFIG.balanced,
    MODEL_CONFIG.fast,
    MODEL_CONFIG.fallback,
    ...Object.values(MODEL_CONFIG.features),
  ]);

  for (const modelId of allModels) {
    try {
      // Send a minimal request to verify the model is accessible
      await client.messages.create({
        model: modelId,
        max_tokens: 1,
        messages: [{ role: 'user', content: 'ping' }],
      });
      console.log(`Model OK: ${modelId}`);
    } catch (err: unknown) {
      if (err instanceof Anthropic.NotFoundError) {
        // Model has been removed — fail startup to force immediate migration
        throw new Error(
          \`STARTUP FAILURE: Model "\${modelId}" not found. ` +
          \`Update MODEL_CONFIG to a supported model and redeploy.\`
        );
      }
      throw err;
    }
  }
}

// Call during application startup before serving traffic
await validateModelConfig(client);

// Model version change detector (runs as a scheduled job)
import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic();

interface ModelCatalogEntry {
  id: string;
  displayName: string;
  createdAt: number;
}

// Fetch the current list of available models
async function fetchAvailableModels(): Promise<ModelCatalogEntry[]> {
  // The Anthropic SDK exposes a models.list() endpoint
  const page = await client.models.list({ limit: 100 });
  return page.data.map((m) => ({
    id: m.id,
    displayName: m.display_name,
    createdAt: m.created_at,
  }));
}

// Compare against last known state and emit alerts for new or removed models
async function detectModelChanges(
  previous: ModelCatalogEntry[],
  current: ModelCatalogEntry[]
): Promise<{ added: string[]; removed: string[] }> {
  const prevIds = new Set(previous.map((m) => m.id));
  const currIds = new Set(current.map((m) => m.id));

  const added = current.filter((m) => !prevIds.has(m.id)).map((m) => m.id);
  const removed = previous.filter((m) => !currIds.has(m.id)).map((m) => m.id);

  return { added, removed };
}

// Scheduled job: run daily, alert on changes
export async function runModelCatalogCheck(
  lastKnownModels: ModelCatalogEntry[]
): Promise<{ models: ModelCatalogEntry[]; changes: { added: string[]; removed: string[] } }> {
  const current = await fetchAvailableModels();
  const changes = await detectModelChanges(lastKnownModels, current);

  if (changes.added.length > 0) {
    await notify('New Claude models available: ' + changes.added.join(', '));
  }
  if (changes.removed.length > 0) {
    // This is critical — a removed model means hardcoded strings are now broken
    await alertSecurity('CRITICAL: Claude models removed: ' + changes.removed.join(', '));
  }

  return { models: current, changes };
}

declare function notify(msg: string): Promise<void>;
declare function alertSecurity(msg: string): Promise<void>;

// eval-suite.ts — model upgrade regression tests
import Anthropic from '@anthropic-ai/sdk';
import { MODEL_CONFIG } from './model-config';

const client = new Anthropic();

interface EvalCase {
  id: string;
  prompt: string;
  expectedPatterns: RegExp[];    // Output must match all patterns
  forbiddenPatterns?: RegExp[];  // Output must not match any
  maxTokens?: number;
  featureKey: keyof typeof MODEL_CONFIG.features;
}

const EVAL_CASES: EvalCase[] = [
  {
    id: 'summarize-01',
    featureKey: 'documentSummarization',
    prompt: 'Summarize in one sentence: The quick brown fox jumped over the lazy dog.',
    expectedPatterns: [/fox/i, /dog/i],
    maxTokens: 100,
  },
  {
    id: 'classify-01',
    featureKey: 'intentClassification',
    prompt: 'Classify as POSITIVE, NEGATIVE, or NEUTRAL: "I love this product!"',
    expectedPatterns: [/POSITIVE/],
    forbiddenPatterns: [/NEGATIVE/, /NEUTRAL/],
    maxTokens: 10,
  },
  {
    id: 'code-review-01',
    featureKey: 'codeReview',
    prompt: 'Find bugs in: function add(a, b) { return a - b; }',
    expectedPatterns: [/subtract|minus|-|wrong|bug|error/i],
    maxTokens: 200,
  },
];

interface EvalResult {
  caseId: string;
  passed: boolean;
  output: string;
  failureReason?: string;
}

export async function runEvalSuite(
  modelOverride?: Partial<typeof MODEL_CONFIG.features>
): Promise<{ passed: number; failed: number; results: EvalResult[] }> {
  const results: EvalResult[] = [];

  for (const ec of EVAL_CASES) {
    const model = modelOverride?.[ec.featureKey] ?? MODEL_CONFIG.features[ec.featureKey];
    const response = await client.messages.create({
      model,
      max_tokens: ec.maxTokens ?? 256,
      messages: [{ role: 'user', content: ec.prompt }],
    });
    const output = response.content[0].type === 'text' ? response.content[0].text : '';

    const missingPattern = ec.expectedPatterns.find((p) => !p.test(output));
    const hitForbidden = ec.forbiddenPatterns?.find((p) => p.test(output));

    const passed = !missingPattern && !hitForbidden;
    results.push({
      caseId: ec.id,
      passed,
      output,
      failureReason: missingPattern
        ? \`Missing expected pattern: \${missingPattern}\`
        : hitForbidden
        ? \`Hit forbidden pattern: \${hitForbidden}\`
        : undefined,
    });
  }

  const passed = results.filter((r) => r.passed).length;
  const failed = results.length - passed;
  return { passed, failed, results };
}
